        best_clique: CliqueSummary | None = None
        for c in cliques:
            if family <= frozenset(c.nodes):
                if best_clique is None or c.size < best_clique.size:
                    best_clique = c
        if best_clique is not None:
            clique_factors[best_clique.id].append(factor)

